import React, { useEffect, useState } from 'react';

import { api } from '../api/api';

interface RentPageProps {
    onRequest?: () => void;
}

interface Rental {
    id: number;
    title: string;
    description: string;
    area: string;
    price: string;
    image_url: string;
}

const RentPage: React.FC<RentPageProps> = ({ onRequest }) => {
    const [rentals, setRentals] = useState<Rental[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        api.getRentals()
            .then(data => {
                setRentals(data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setError('Не удалось загрузить объекты аренды');
                setLoading(false);
            });
    }, []);

    if (loading) return <div className="page-shell text-center font-semibold text-graphite-500">Загрузка...</div>;

    if (error) return <div className="page-shell text-center font-semibold text-red-600">{error}</div>;

    return (
        <div className="page-shell">
            <div className="mb-10">
                <h1 className="page-title">Аренда</h1>
            </div>

            <div className="grid grid-cols-1 gap-7 md:grid-cols-2">
                {rentals.map(item => (
                    <div key={item.id} className="card-hover overflow-hidden p-4">
                        <div className="relative overflow-hidden rounded-[1.25rem] bg-graphite-100">
                            <img
                                src={item.image_url || 'https://via.placeholder.com/400x250?text=Фото+объекта'}
                                alt={item.title}
                                className="h-64 w-full object-cover transition duration-500 hover:scale-105"
                            />
                            <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-graphite-950/80 to-transparent p-5 text-white">
                                <span className="rounded-full bg-white/20 px-3 py-1 text-xs font-bold backdrop-blur">{item.area}</span>
                            </div>
                        </div>

                        <div className="p-2 pt-5">
                            <h3 className="font-display text-2xl font-black text-graphite-950">{item.title}</h3>
                            <p className="mt-3 text-sm leading-6 text-graphite-600">{item.description}</p>

                            <div className="mt-6 flex flex-col gap-4 rounded-2xl border border-graphite-100 bg-graphite-50/80 p-4 sm:flex-row sm:items-center sm:justify-between">
                                <div>
                                    <span className="text-xs font-bold uppercase tracking-[0.18em] text-graphite-400">Стоимость</span>
                                    <p className="mt-1 text-xl font-black text-factory-700">{item.price}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {onRequest && (
                <div className="mt-10 text-center">
                    <button type="button" onClick={onRequest} className="btn-primary px-8">
                        Узнать подробнее
                    </button>
                </div>
            )}
        </div>
    );
};

export default RentPage;
